import { useEffect, useState } from 'react'

const INTERCOM_APP_ID = 'j9rgik9b'
const INTERCOM_API_BASE = 'https://api-iam.eu.intercom.io'
const INTERCOM_SCRIPT_URL = `https://widget.intercom.io/widget/${INTERCOM_APP_ID}`

export const IntercomTest = () => {
  const [isIntercomLoaded, setIsIntercomLoaded] = useState(false)
  const [tourId, setTourId] = useState('21407')

  useEffect(() => {
    const existingScript = document.querySelector(`script[src="${INTERCOM_SCRIPT_URL}"]`)
    const isIntercomBooted = (window as any).Intercom?.('booted')

    console.log('Script exists:', !!existingScript, 'Intercom booted:', isIntercomBooted)

    if (!existingScript) {
      const script = document.createElement('script')
      script.src = INTERCOM_SCRIPT_URL
      script.async = true
      script.onload = () => {
        console.log('Intercom script loaded, booting...')
        console.log('Window.Intercom before boot:', (window as any).Intercom)
        ;(window as any).Intercom?.('boot', {
          app_id: INTERCOM_APP_ID,
          api_base: INTERCOM_API_BASE,
          hide_default_launcher: true,
          hide_notifications: true,
          name: 'Test User',
          email: 'test@wpp.com',
          user_id: 'test-user-poc-123',
        })
        console.log('Window.Intercom after boot:', (window as any).Intercom)
        ;(window as any).Intercom?.('update')
        // Wait for Intercom to be fully ready
        setTimeout(() => {
          setIsIntercomLoaded(true)
          console.log('Intercom marked as ready')
        }, 2000)
      }
      script.onerror = () => {
        console.error('Failed to load Intercom script')
      }
      document.head.appendChild(script)
    } else if (!isIntercomBooted) {
      console.log('Script exists but Intercom not booted, booting now...')
      ;(window as any).Intercom?.('boot', {
        app_id: INTERCOM_APP_ID,
        api_base: INTERCOM_API_BASE,
        hide_default_launcher: true,
        hide_notifications: true,
        name: 'Test User',
        email: 'test@wpp.com',
        user_id: 'test-user-poc-123',
      })
      // ;(window as any).Intercom?.('update')
      setTimeout(() => {
        setIsIntercomLoaded(true)
        console.log('Intercom marked as ready after re-boot')
      }, 2000)
    } else {
      setIsIntercomLoaded(true)
      console.log('Intercom already booted, skipping')
    }
  }, [])

  const handleStartTour = () => {
    console.log('Starting Intercom tour with ID:', tourId)
    console.log('__wppStartIntercomTour available:', !!(window as any).__wppStartIntercomTour)
    console.log('Window.Intercom available:', !!(window as any).Intercom)

    if ((window as any).__wppStartIntercomTour) {
      console.log('Triggering tour via parent (WPP Platform context)')
      ;(window as any).__wppStartIntercomTour(tourId)
    } else {
      console.log('Triggering tour directly (standalone context)')
      ;(window as any).Intercom?.('startTour', tourId)
    }
  }

  return (
    <div
      style={{ padding: '20px', border: '1px solid #ccc', borderRadius: '8px', margin: '20px 0' }}
      data-intercom-target="intercom-test-container"
    >
      <h3 data-intercom-target="intercom-test-title">Intercom Test Component</h3>
      <p data-intercom-target="intercom-test-status">Status: {isIntercomLoaded ? '✅ Loaded' : '⏳ Loading...'}</p>
      <div style={{ marginBottom: '15px' }} data-intercom-target="intercom-tour-id-input">
        <label htmlFor="tourId" style={{ marginRight: '10px' }}>
          Tour ID:
        </label>
        <input
          id="tourId"
          type="number"
          value={tourId}
          onChange={e => setTourId(e.target.value)}
          style={{
            padding: '8px',
            borderRadius: '4px',
            border: '1px solid #ccc',
            width: '100px',
          }}
        />
      </div>
      <button
        onClick={handleStartTour}
        disabled={!isIntercomLoaded}
        data-intercom-target="intercom-start-tour-button"
        style={{
          padding: '10px 20px',
          backgroundColor: isIntercomLoaded ? '#26c647' : '#ccc',
          color: 'white',
          border: 'none',
          borderRadius: '4px',
          cursor: isIntercomLoaded ? 'pointer' : 'not-allowed',
        }}
      >
        Start Tour
      </button>
    </div>
  )
}
