import { useOs } from '@wppopen/react'
import React from 'react'
import { BrowserRouter, Navigate, Route, Routes } from 'react-router-dom'

import styles from 'app/App.module.scss'
import { Header } from 'app/header/Header'
import { IntercomTestPage } from 'pages/intercom/IntercomTestPage'
import { IntercomTourBuilderPage } from 'pages/intercom/IntercomTourBuilderPage'
import { NavigationAndWorkspacesPage } from 'pages/navigationAndWorkspaces/NavigationAndWorkspacesPage'
import { WelcomePage } from 'pages/welcome/WelcomePage'

export function App() {
  /**
   * This hook is provided by the utility package for more convenient work with OS context
   * @return osContext
   * - is a subscribe function that returns you the main context object with MicroAppContext data
   * @return osApi
   * - methods to fire actions on the parent OS level
   *
   * Read more about it in the README file
   */
  const { osContext } = useOs()

  return (
    <BrowserRouter
      future={{ v7_startTransition: true, v7_relativeSplatPath: true }}
      basename={osContext.baseUrl || undefined}
    >
      <div className={styles.container}>
        <Header />
        <div className={styles.pageContent}>
          <Routes>
            <Route path="/welcome" element={<WelcomePage />} />
            <Route path="/intercom-test" element={<IntercomTestPage />} />
            <Route path="/intercom-tour-builder" element={<IntercomTourBuilderPage />} />
            <Route path="/navigation-workspaces" element={<NavigationAndWorkspacesPage />} />
            <Route index element={<Navigate replace to="/intercom-test" />} />
          </Routes>
        </div>
      </div>
    </BrowserRouter>
  )
}
