import { useEffect, useState } from 'react'
import { useSearchParams } from 'react-router-dom'

export const IntercomTourBuilderPage = () => {
  const [searchParams] = useSearchParams()
  const [isIntercomLoaded, setIsIntercomLoaded] = useState(false)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    const standaloneIntercomBoot = searchParams.get('standaloneIntercomBoot') === 'true'
    const appId = searchParams.get('appId') || 'j9rgik9b'
    const apiBase = searchParams.get('apiBase') || 'https://api-iam.eu.intercom.io'
    const email = searchParams.get('email') || 'test@wpp.com'
    const userId = searchParams.get('userId') || 'test-user-poc-123'
    const name = searchParams.get('name') || 'Test User'

    if (!standaloneIntercomBoot) {
      setError('Missing standaloneIntercomBoot=true parameter')
      return
    }

    console.log('Intercom Tour Builder - booting with config:', {
      appId,
      apiBase,
      email,
      userId,
      name,
    })

    const scriptUrl = `https://widget.intercom.io/widget/${appId}`
    const existingScript = document.querySelector(`script[src="${scriptUrl}"]`)

    if (!existingScript) {
      const script = document.createElement('script')
      script.src = scriptUrl
      script.async = true
      script.onload = () => {
        console.log('Intercom script loaded, booting...')
        ;(window as any).Intercom?.('boot', {
          app_id: appId,
          api_base: apiBase,
          hide_default_launcher: true,
          hide_notifications: true,
          name,
          email,
          user_id: userId,
        })
        ;(window as any).Intercom?.('update')
        setTimeout(() => {
          setIsIntercomLoaded(true)
          console.log('Intercom ready for tour building')
        }, 2000)
      }
      script.onerror = () => {
        console.error('Failed to load Intercom script')
        setError('Failed to load Intercom script')
      }
      document.head.appendChild(script)
    } else {
      setIsIntercomLoaded(true)
    }
  }, [searchParams])

  if (error) {
    return (
      <div style={{ padding: '20px', color: 'red' }}>
        <h2>Error</h2>
        <p>{error}</p>
      </div>
    )
  }

  return (
    <div style={{ padding: '20px' }}>
      <h1>Intercom Tour Builder</h1>
      <p>Status: {isIntercomLoaded ? '✅ Ready for tour building' : '⏳ Loading Intercom...'}</p>
      <p style={{ color: '#666', fontSize: '14px' }}>
        This page is designed to be used as a standalone app in Intercom's tour builder. Add this URL with query
        parameters to your Intercom workspace.
      </p>
    </div>
  )
}
