import { DefaultHierarchyLevelType, HierarchyCustomNodeType, } from '../types';
export const getRootHierarchyLevel = (tenant) => tenant.hierarchyLevels.find((level) => level.type === DefaultHierarchyLevelType.Tenant);
export const getChildHierarchyLevels = (tenant) => tenant.hierarchyLevels.filter((level) => level.type !== DefaultHierarchyLevelType.Tenant);
export const isDefaultHierarchyLevelType = (levelType) => {
    const defaultTypes = Object.values(DefaultHierarchyLevelType);
    return defaultTypes.includes(levelType);
};
export const isDefaultChildHierarchyLevelType = (levelType) => isDefaultHierarchyLevelType(levelType) && levelType !== DefaultHierarchyLevelType.Tenant;
export const getVisibleHierarchyLevels = (tenant) => tenant.hierarchyLevels.filter((level, index) => !tenant.flags.isFirstLevelHidden || index !== 1);
/**
 * Returns navigation node type.
 * For custom hierarchy nodes it returns the actual custom hierarchy level name.
 */
export const getNavigationNodeType = (node) => node.type === HierarchyCustomNodeType ? node.customTypeName : node.type;
